SELECT MENU_CODE
FROM COMTNMENUINFO M
LEFT JOIN COMTCCMMNDETAILCODE D
    ON D.CODE = M.MENU_CODE
WHERE COALESCE(D.USE_AT, 'Y') = 'Y'
  AND COALESCE(M.USE_AT, 'Y') = 'Y'
  AND (
        M.MENU_URL = #{_parameter}
     OR ('/' || M.MENU_URL) = #{_parameter}
     OR (
        #{_parameter} = '/admin/member/approve'
        AND M.MENU_URL = '/admin/app?route=member-approve'
     ) OR (
        #{_parameter} = '/admin/member/company-approve'
        AND M.MENU_URL = '/admin/app?route=company-approve'
     ) OR (
        #{_parameter} = '/admin/member/edit'
        AND M.MENU_URL = '/admin/app?route=member-edit'
     ) OR (
        #{_parameter} = '/admin/member/detail'
        AND M.MENU_URL = '/admin/app?route=member-detail'
     ) OR (
        #{_parameter} = '/admin/member/reset_password'
        AND M.MENU_URL = '/admin/app?route=password-reset'
     ) OR (
        #{_parameter} = '/admin/member/list'
        AND M.MENU_URL = '/admin/app?route=member-list'
     ) OR (
        #{_parameter} IN ('/admin/member/admin_list', '/admin/member/admin-list')
        AND M.MENU_URL = '/admin/app?route=admin-list'
     ) OR (
        #{_parameter} = '/admin/member/company_list'
        AND M.MENU_URL = '/admin/app?route=company-list'
     ) OR (
        #{_parameter} = '/admin/member/company_detail'
        AND M.MENU_URL = '/admin/app?route=company-detail'
     ) OR (
        #{_parameter} = '/admin/member/company_account'
        AND M.MENU_URL = '/admin/app?route=company-account'
     ) OR (
        #{_parameter} = '/admin/member/admin_account'
        AND M.MENU_URL = '/admin/app?route=admin-create'
     ) OR (
        #{_parameter} = '/admin/member/admin_account/permissions'
        AND M.MENU_URL = '/admin/app?route=admin-permission'
     ) OR (
        #{_parameter} IN ('/admin/auth/group', '/admin/member/auth-group', '/admin/system/role')
        AND M.MENU_URL = '/admin/app?route=auth-group'
     ) OR (
        #{_parameter} IN ('/admin/member/auth-change', '/admin/system/auth-change')
        AND M.MENU_URL = '/admin/app?route=auth-change'
     ) OR (
        #{_parameter} IN ('/admin/member/dept-role-mapping', '/admin/system/dept-role-mapping')
        AND M.MENU_URL = '/admin/app?route=dept-role'
     ) OR (
        #{_parameter} = '/admin/system/sr-workbench'
        AND M.MENU_URL = '/admin/app?route=sr-workbench'
     )
  )
ORDER BY M.MENU_CODE
LIMIT 1

SELECT COUNT(*)
FROM COMTNAUTHORFUNCTIONRELATE
WHERE AUTHOR_CODE = #{authorCode}
  AND FEATURE_CODE = #{featureCode}

SELECT COUNT(*)
FROM COMTNAUTHORFUNCTIONRELATE
WHERE FEATURE_CODE = #{_parameter}

SELECT COUNT(*)
FROM COMTNUSERFEATUREOVERRIDE
WHERE FEATURE_CODE = #{_parameter}

SELECT FEATURE_CODE AS featureCode, COUNT(*) AS referenceCount FROM COMTNAUTHORFUNCTIONRELATE WHERE FEATURE_CODE IN
#{featureCode}
GROUP BY FEATURE_CODE

SELECT FEATURE_CODE AS featureCode, COUNT(*) AS referenceCount FROM COMTNUSERFEATUREOVERRIDE WHERE FEATURE_CODE IN
#{featureCode}
GROUP BY FEATURE_CODE

SELECT COUNT(*) FROM COMTNEMPLYRSCRTYESTBS S INNER JOIN COMTNEMPLYRINFO E ON E.ESNTL_ID = S.SCRTY_DTRMN_TRGET_ID LEFT JOIN COMTNAUTHORINFO A ON A.AUTHOR_CODE = S.AUTHOR_CODE WHERE S.AUTHOR_CODE IS NOT NULL AND S.AUTHOR_CODE != ''
AND E.ORGNZT_ID = #{orgnztId}
AND COALESCE(E.INSTT_ID, '') = #{insttId}
AND ( LOWER(E.EMPLYR_ID) LIKE '%' || LOWER(#{searchKeyword}) || '%' OR LOWER(COALESCE(E.USER_NM, '')) LIKE '%' || LOWER(#{searchKeyword}) || '%' OR LOWER(S.AUTHOR_CODE) LIKE '%' || LOWER(#{searchKeyword}) || '%' OR LOWER(COALESCE(A.AUTHOR_NM, '')) LIKE '%' || LOWER(#{searchKeyword}) || '%' )

SELECT E.EMPLYR_ID AS emplyrId, E.USER_NM AS userNm, COALESCE(E.ORGNZT_ID, '') AS orgnztId, COALESCE(E.EMPLYR_STTUS_CODE, '') AS emplyrSttusCode, COALESCE(S.AUTHOR_CODE, '') AS authorCode, COALESCE(A.AUTHOR_NM, '') AS authorNm FROM COMTNEMPLYRSCRTYESTBS S INNER JOIN COMTNEMPLYRINFO E ON E.ESNTL_ID = S.SCRTY_DTRMN_TRGET_ID LEFT JOIN COMTNAUTHORINFO A ON A.AUTHOR_CODE = S.AUTHOR_CODE WHERE S.AUTHOR_CODE IS NOT NULL AND S.AUTHOR_CODE != ''
AND E.ORGNZT_ID = #{orgnztId}
AND COALESCE(E.INSTT_ID, '') = #{insttId}
AND ( LOWER(E.EMPLYR_ID) LIKE '%' || LOWER(#{searchKeyword}) || '%' OR LOWER(COALESCE(E.USER_NM, '')) LIKE '%' || LOWER(#{searchKeyword}) || '%' OR LOWER(S.AUTHOR_CODE) LIKE '%' || LOWER(#{searchKeyword}) || '%' OR LOWER(COALESCE(A.AUTHOR_NM, '')) LIKE '%' || LOWER(#{searchKeyword}) || '%' )
ORDER BY E.EMPLYR_ID LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

SELECT COALESCE(INSTT_ID, '')
FROM COMTNEMPLYRINFO
WHERE EMPLYR_ID = #{value}

SELECT B.INSTT_ID AS insttId, B.CMPNY_NM AS cmpnyNm, COALESCE(B.DEPT_NM, '') AS deptNm, B.MEMBER_COUNT AS memberCount, COALESCE(R.AUTHOR_CODE, '') AS authorCode, COALESCE(A.AUTHOR_NM, '') AS authorNm, COALESCE(R.USE_AT, 'Y') AS useAt FROM ( SELECT TRIM(INSTT_ID) AS INSTT_ID, MAX(CMPNY_NM) AS CMPNY_NM, COALESCE(DEPT_NM, '') AS DEPT_NM, COUNT(*) AS MEMBER_COUNT FROM COMTNENTRPRSMBER WHERE TRIM(COALESCE(INSTT_ID, '')) != ''
AND PROJECT_ID = #{projectId}
GROUP BY TRIM(INSTT_ID), COALESCE(DEPT_NM, '') ) B LEFT JOIN COMTNDEPTAUTHORRELATE R ON R.INSTT_ID = B.INSTT_ID AND R.DEPT_NM = B.DEPT_NM LEFT JOIN COMTNAUTHORINFO A ON A.AUTHOR_CODE = R.AUTHOR_CODE ORDER BY B.CMPNY_NM, B.DEPT_NM

SELECT B.INSTT_ID AS insttId, B.CMPNY_NM AS cmpnyNm, COALESCE(B.DEPT_NM, '') AS deptNm, B.MEMBER_COUNT AS memberCount, COALESCE(R.AUTHOR_CODE, '') AS authorCode, COALESCE(A.AUTHOR_NM, '') AS authorNm, COALESCE(R.USE_AT, 'Y') AS useAt FROM ( SELECT TRIM(INSTT_ID) AS INSTT_ID, MAX(CMPNY_NM) AS CMPNY_NM, COALESCE(DEPT_NM, '') AS DEPT_NM, COUNT(*) AS MEMBER_COUNT FROM COMTNENTRPRSMBER WHERE TRIM(COALESCE(INSTT_ID, '')) = #{insttId}
AND PROJECT_ID = #{projectId}
AND COALESCE(DEPT_NM, '') = #{deptNm} GROUP BY TRIM(INSTT_ID), COALESCE(DEPT_NM, '') ) B LEFT JOIN COMTNDEPTAUTHORRELATE R ON R.INSTT_ID = B.INSTT_ID AND R.DEPT_NM = B.DEPT_NM LEFT JOIN COMTNAUTHORINFO A ON A.AUTHOR_CODE = R.AUTHOR_CODE

SELECT E.ENTRPRS_MBER_ID AS userId, COALESCE(E.APPLCNT_NM, '') AS userNm, TRIM(E.INSTT_ID) AS insttId, COALESCE(E.CMPNY_NM, '') AS cmpnyNm, COALESCE(E.DEPT_NM, '') AS deptNm, COALESCE(S.AUTHOR_CODE, '') AS authorCode, COALESCE(A.AUTHOR_NM, '') AS authorNm FROM COMTNENTRPRSMBER E LEFT JOIN COMTNEMPLYRSCRTYESTBS S ON E.ESNTL_ID = S.SCRTY_DTRMN_TRGET_ID LEFT JOIN COMTNAUTHORINFO A ON A.AUTHOR_CODE = S.AUTHOR_CODE WHERE TRIM(COALESCE(E.INSTT_ID, '')) = #{insttId}
AND E.PROJECT_ID = #{projectId}
AND ( E.ENTRPRS_MBER_ID LIKE '%' || #{searchKeyword} || '%' OR E.APPLCNT_NM LIKE '%' || #{searchKeyword} || '%' OR E.CMPNY_NM LIKE '%' || #{searchKeyword} || '%' OR E.DEPT_NM LIKE '%' || #{searchKeyword} || '%' )
ORDER BY E.SBSCRB_DE DESC, E.ENTRPRS_MBER_ID DESC

SELECT E.ENTRPRS_MBER_ID AS userId, COALESCE(E.APPLCNT_NM, '') AS userNm, TRIM(E.INSTT_ID) AS insttId, COALESCE(E.CMPNY_NM, '') AS cmpnyNm, COALESCE(E.DEPT_NM, '') AS deptNm, COALESCE(S.AUTHOR_CODE, '') AS authorCode, COALESCE(A.AUTHOR_NM, '') AS authorNm FROM COMTNENTRPRSMBER E LEFT JOIN COMTNEMPLYRSCRTYESTBS S ON E.ESNTL_ID = S.SCRTY_DTRMN_TRGET_ID LEFT JOIN COMTNAUTHORINFO A ON A.AUTHOR_CODE = S.AUTHOR_CODE WHERE TRIM(COALESCE(E.INSTT_ID, '')) = #{insttId}
AND E.PROJECT_ID = #{projectId}
AND E.ENTRPRS_MBER_ID = #{userId}

SELECT ESNTL_ID
FROM COMTNEMPLYRINFO
WHERE EMPLYR_ID = #{_parameter}

SELECT ESNTL_ID
FROM COMTNENTRPRSMBER
WHERE ENTRPRS_MBER_ID = #{userId}

    AND PROJECT_ID = #{projectId}

SELECT S.AUTHOR_CODE
FROM COMTNENTRPRSMBER E
INNER JOIN COMTNEMPLYRSCRTYESTBS S
    ON E.ESNTL_ID = S.SCRTY_DTRMN_TRGET_ID
WHERE E.ENTRPRS_MBER_ID = #{userId}

    AND E.PROJECT_ID = #{projectId}

SELECT TRIM(COALESCE(INSTT_ID, ''))
FROM COMTNENTRPRSMBER
WHERE ENTRPRS_MBER_ID = #{userId}

    AND PROJECT_ID = #{projectId}

SELECT COUNT(*)
FROM COMTNEMPLYRSCRTYESTBS
WHERE SCRTY_DTRMN_TRGET_ID = #{_parameter}

